class LoopDetector:
    def __init__(self):
        self.history = []

    def check(self, action):
        self.history.append(action)
        if len(self.history) >= 3:
            if len(set(self.history[-3:])) == 1:
                return True
        return False

task_decomposition.code:
def decompose_task(task):
    steps = []
    if 'и' in task or 'затем' in task:
        parts = task.replace('затем', 'и').split('и')
        for i, part in enumerate(parts):
            steps.append({
                'step': i+1,
                'action': part.strip(),
                'status': 'pending'
            })
    else:
        steps.append({'step': 1, 'action': task, 'status': 'pending'})
    return steps

caching.code:
cache = {}
def cached_operation(key, operation):
    if key in cache:
        return cache[key]
    result = operation()
    cache[key] = result
    return result

batch_processing.code:
def batch_files(operations):
    grouped = {'read': [], 'write': []}
    for op in operations:
        grouped[op['type']].append(op)
    return grouped

pattern_learning.code:
def learn_patterns(log):
    sequences = []
    current = []
    for entry in log:
        if entry.get('success'):
            current.append(entry['action'])
        else:
            if len(current) > 2:
                sequences.append(current)
            current = []
    return sequences
